if global.gamePaused=false
{
  if bDestroyMe=1
  {
    for(i=0;i<12;i+=1)
    {
      tEffect=instance_create(x+(random(48)*image_xscale),y-random(48),oEffectB)
      tEffect.type=3; tEffect.image_speed=0; tEffect.image_index=choose(0,1); tEffect.sprite_index=sPauseM_SkillLv
